146→// hookOutput is the JSON structure Claude Code expects from hook stdout.
147→type hookOutput struct {
148→	SystemMessage    string            `json:"systemMessage,omitempty"`
149→	HookSpecificOut  *hookSpecificOut  `json:"hookSpecificOutput,omitempty"`
150→}
151→
152→type hookSpecificOut struct {
153→	HookEventName     string `json:"hookEventName"`
154→	AdditionalContext string `json:"additionalContext,omitempty"`
155→}
