157→// runSessionStart outputs JSON with systemMessage (visible banner) and
158→// additionalContext (LLM context) for the SessionStart hook.
159→// Also captures the session in DB + log.
160→func runSessionStart() error {
161→	// Read stdin (Claude Code sends session info)
162→	input, _ := session.ReadStdin()
163→
164→	// Capture session in DB (graceful — don't fail the hook if DB is missing)
165→	if input != nil && input.SessionID != "" && db.Exists() {
166→		if d, err := db.Open(); err == nil {
167→			db.EnsureSessionTables(d)
168→			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
169→			session.AddEvent(d, input.SessionID, "session_start", input)
170→			d.Close()
171→		}
172→		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
173→		session.FlushLog()
174→	}
175→
176→	// Sync permissions — ensures existing users get any new permissions
177→	// added in later versions. Graceful — never fails the hook.
178→	project.SyncPermissions()
179→
180→	// Auto-update check (non-blocking, cached)
181→	updateMsg := checkAndAutoUpdate()
182→
183→	s := gatherStatus()
184→
185→	banner := buildBanner(s)
186→	if updateMsg != "" {
187→		banner += "\n  " + updateMsg
188→	}
189→	context := buildPromptContext(s)
190→
191→	out := hookOutput{
192→		SystemMessage: banner,
193→		HookSpecificOut: &hookSpecificOut{
194→			HookEventName:     "SessionStart",
195→			AdditionalContext: context,
196→		},
197→	}
198→
199→	enc := json.NewEncoder(os.Stdout)
200→	return enc.Encode(out)
201→}
