203→// runUserPrompt captures a user prompt submission event.
204→func runUserPrompt() error {
205→	input, err := session.ReadStdin()
206→	if err != nil || input == nil || input.SessionID == "" {
207→		return nil // graceful no-op
208→	}
209→
210→	if !db.Exists() {
211→		return nil
212→	}
213→	d, err := db.Open()
214→	if err != nil {
215→		return nil
216→	}
217→	defer d.Close()
218→
219→	db.EnsureSessionTables(d)
220→	session.AddEvent(d, input.SessionID, "prompt", input)
221→
222→	// Log without prompt content — keep logs lightweight
223→	session.Logger().Info("prompt", "session_id", input.SessionID)
224→	session.FlushLog()
225→	return nil
226→}
