228→// runStop captures a stop event and creates a checkpoint.
229→func runStop() error {
230→	input, err := session.ReadStdin()
231→	if err != nil || input == nil || input.SessionID == "" {
232→		return nil
233→	}
234→
235→	if !db.Exists() {
236→		return nil
237→	}
238→	d, err := db.Open()
239→	if err != nil {
240→		return nil
241→	}
242→	defer d.Close()
243→
244→	db.EnsureSessionTables(d)
245→	session.AddEvent(d, input.SessionID, "stop", input)
246→	if len(input.ModifiedFiles) > 0 {
247→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
248→	}
249→
250→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
251→	session.FlushLog()
252→	return nil
253→}
