255→// runSessionEnd marks a session as ended.
256→func runSessionEnd() error {
257→	input, err := session.ReadStdin()
258→	if err != nil || input == nil || input.SessionID == "" {
259→		return nil
260→	}
261→
262→	if !db.Exists() {
263→		return nil
264→	}
265→	d, err := db.Open()
266→	if err != nil {
267→		return nil
268→	}
269→	defer d.Close()
270→
271→	db.EnsureSessionTables(d)
272→	session.EndSession(d, input.SessionID)
273→	session.AddEvent(d, input.SessionID, "session_end", input)
274→
275→	session.Logger().Info("session-end", "session_id", input.SessionID)
276→	session.FlushLog()
277→	return nil
278→}
