280→func buildBanner(s *sessionStatus) string {
281→	var b strings.Builder
282→	ver := fmt.Sprintf("nurge %s", buildVersion)
283→
284→	if !s.configLoaded {
285→		fmt.Fprintf(&b, "\n\n%s\n", ver)
286→		b.WriteString("  Run: nurge to get started")
287→		return b.String()
288→	}
289→
290→	// --- Pre-setup: no connectors yet ---
291→	hasConnectors := false
292→	for _, c := range s.connectors {
293→		if c.Connected {
294→			hasConnectors = true
295→			break
296→		}
297→	}
298→	if !hasConnectors {
299→		fmt.Fprintf(&b, "\n\n%s\n", ver)
300→		b.WriteString("  Run /nurge:setup to connect your email and get started.")
301→		return b.String()
302→	}
303→
304→	// --- Setup in progress ---
305→	if !s.setupCompleted {
306→		name := s.settings["user.name"]
307→		if name != "" {
308→			fmt.Fprintf(&b, "\n\n%s — Hey %s, setup in progress.\n", ver, name)
309→		} else {
310→			fmt.Fprintf(&b, "\n\n%s — Setup in progress.\n", ver)
311→		}
312→		b.WriteString("  Run /nurge:setup to continue where you left off.")
313→		return b.String()
314→	}
315→
316→	// --- Post-setup: compact rotating dashboard ---
317→	name := s.settings["user.name"]
318→	if name != "" {
319→		fmt.Fprintf(&b, "\n\n%s — Hey %s\n", ver, name)
320→	} else {
321→		fmt.Fprintf(&b, "\n\n%s\n", ver)
322→	}
323→
324→	// Always show: KPI progress (the one thing that matters most)
325→	if s.weeklyStats != nil && s.weeklyStats.OutboundSent > 0 {
326→		fmt.Fprintf(&b, "  This week: %d emails sent", s.weeklyStats.OutboundSent)
327→		if s.weeklyStats.UniqueContacts > 0 {
328→			fmt.Fprintf(&b, " → %d contacts", s.weeklyStats.UniqueContacts)
329→		}
330→		kpiTarget := s.settings["kpi.daily_emails"]
331→		if kpiTarget != "" {
332→			fmt.Fprintf(&b, " (target: %s/day)", kpiTarget)
333→		}
334→		b.WriteString("\n")
335→	} else {
336→		goal := s.settings["kpi.goal"]
337→		if goal != "" {
338→			fmt.Fprintf(&b, "  Goal: %s — no emails sent this week yet\n", goal)
339→		}
340→	}
341→
342→	// Rotate one additional insight based on day-of-year
343→	// This keeps the banner fresh without overwhelming
344→	slot := time.Now().YearDay() % 5
345→	switch slot {
346→	case 0: // Sending health
347→		warmup := s.settings["sending.warmup_status"]
348→		domainType := s.settings["sending.domain_type"]
349→		if warmup == "fresh" {
350→			b.WriteString("  Domain is fresh — warmup in progress, conservative limits active\n")
351→		} else if domainType == "primary" {
352→			b.WriteString("  Sending from primary domain — consider a dedicated outbound domain\n")
353→		} else {
354→			fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
355→		}
356→	case 1: // Data snapshot
357→		fmt.Fprintf(&b, "  Data: %s emails", formatCount(s.emailTotal))
358→		if s.outboundTotal > 0 {
359→			fmt.Fprintf(&b, " (%d outbound)", s.outboundTotal)
360→		}
361→		if s.contactCount > 0 {
362→			fmt.Fprintf(&b, " | %d contacts", s.contactCount)
363→		}
364→		b.WriteString("\n")
365→	case 2: // Learnings
366→		if s.learningCount > 0 {
367→			fmt.Fprintf(&b, "  %d learnings captured — skills improving with every session\n", s.learningCount)
368→		} else {
369→			fmt.Fprintf(&b, "  %d skills active | Start sending to build learnings\n", s.skillCount)
370→		}
371→	case 3: // Connected services
372→		var connList []string
373→		for id, c := range s.connectors {
374→			if c.Connected {
375→				connList = append(connList, capitalize(id))
376→			}
377→		}
378→		fmt.Fprintf(&b, "  Connected: %s | %d skills active\n", strings.Join(connList, ", "), s.skillCount)
379→	case 4: // Quick action suggestion
380→		actions := []string{
381→			"\"research [company]\" — deep-dive a prospect",
382→			"\"write an email to [persona] at [company]\"",
383→			"\"/nurge:review\" — check your KPI progress",
384→			"\"show my pipeline\" — see what needs attention",
385→		}
386→		pick := time.Now().YearDay() / 5 % len(actions)
387→		fmt.Fprintf(&b, "  Try: %s\n", actions[pick])
388→	}
389→
390→	return b.String()
391→}
