393→func buildPromptContext(s *sessionStatus) string {
394→	var b strings.Builder
395→
396→	if !s.configLoaded || !s.setupCompleted {
397→		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
398→		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
399→		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
400→		return b.String()
401→	}
402→
403→	// User context
404→	name := s.settings["user.name"]
405→	role := s.settings["user.role"]
406→	if name != "" {
407→		fmt.Fprintf(&b, "User: %s", name)
408→		if role != "" {
409→			fmt.Fprintf(&b, " (%s)", role)
410→		}
411→		b.WriteString("\n")
412→	}
413→
414→	b.WriteString("You are in a Nurge outbound sales workspace.\n")
415→	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced (%d outbound). %d contacts. %d skills active.\n",
416→		formatCount(s.emailTotal), s.outboundTotal, s.contactCount, s.skillCount)
417→
418→	// KPI context
419→	goal := s.settings["kpi.goal"]
420→	dailyTarget := s.settings["kpi.daily_emails"]
421→	weeklyMeetings := s.settings["kpi.weekly_meetings"]
422→	if goal != "" {
423→		fmt.Fprintf(&b, "Outbound goal: %s.", goal)
424→		if dailyTarget != "" {
425→			fmt.Fprintf(&b, " Daily target: %s emails.", dailyTarget)
426→		}
427→		if weeklyMeetings != "" {
428→			fmt.Fprintf(&b, " Weekly meeting target: %s.", weeklyMeetings)
429→		}
430→		b.WriteString("\n")
431→	}
432→
433→	// Sending context
434→	warmup := s.settings["sending.warmup_status"]
435→	domainType := s.settings["sending.domain_type"]
436→	if warmup == "fresh" {
437→		b.WriteString("IMPORTANT: Domain is fresh/not warmed up. Enforce conservative sending limits. Do not exceed daily target.\n")
438→	}
439→	if domainType == "primary" {
440→		b.WriteString("Note: User is sending from primary business domain. Be conservative with volume.\n")
441→	}
442→
443→	// Geography / compliance
444→	geo := s.settings["prospects.geography"]
445→	if geo != "" {
446→		fmt.Fprintf(&b, "Prospect geography: %s.", geo)
447→		if strings.Contains(strings.ToLower(geo), "eu") || strings.Contains(strings.ToLower(geo), "europe") {
448→			b.WriteString(" GDPR applies — ensure legitimate interest basis for outreach.")
449→		}
450→		b.WriteString("\n")
451→	}
452→
453→	// Rules
454→	b.WriteString("Rules:\n")
455→	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
456→	b.WriteString("- For ICP, personas, and product context: nurge config show --format json\n")
457→	b.WriteString("- For email patterns and insights: nurge context generate --format json\n")
458→	b.WriteString("- For email stats: nurge emails stats --format json\n")
459→	b.WriteString("- When sending emails: nurge send (always get user approval first)\n")
460→	b.WriteString("- When researching prospects: use WebSearch with multiple angles, check company legal pages (mentions légales, impressum), cross-reference before drafting")
461→
462→	if len(s.skillNames) > 0 {
463→		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
464→	}
465→
466→	return b.String()
467→}
