469→// --- Auto-update ---
470→
471→const (
472→	updateCacheFile = ".nurge/update_check.json"
473→	updateCheckTTL  = 24 * time.Hour
474→	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
475→)
476→
477→type updateCache struct {
478→	LatestVersion string `json:"latest_version"`
479→	CheckedAt     string `json:"checked_at"`
480→	UpdatedAt     string `json:"updated_at,omitempty"`
481→}
482→
483→// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
484→// Returns a message for the banner, or empty string.
485→func checkAndAutoUpdate() string {
486→	// Read cache
487→	cache := readUpdateCache()
488→
489→	// If checked recently, just report
490→	if cache != nil && cache.CheckedAt != "" {
491→		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
492→		if err == nil && time.Since(checkedAt) < updateCheckTTL {
493→			// Cache is fresh — check if we just updated
494→			if cache.UpdatedAt != "" {
495→				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
496→				if err == nil && time.Since(updatedAt) < 5*time.Minute {
497→					// Clear the updated flag for next time
498→					cache.UpdatedAt = ""
499→					writeUpdateCache(cache)
500→					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
501→				}
502→			}
503→			return ""
504→		}
505→	}
506→
507→	// Check for latest version (with timeout)
508→	latest := fetchLatestVersion()
509→	if latest == "" {
510→		// Network failed — update cache timestamp so we don't retry immediately
511→		if cache == nil {
512→			cache = &updateCache{}
513→		}
514→		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
515→		writeUpdateCache(cache)
516→		return ""
517→	}
518→
519→	// Save to cache
520→	if cache == nil {
521→		cache = &updateCache{}
522→	}
523→	cache.LatestVersion = latest
524→	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
525→
526→	// Compare: if current version matches latest, no update needed
527→	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
528→		writeUpdateCache(cache)
529→		return ""
530→	}
531→
532→	// Different version — auto-update
533→	if runAutoUpdate() {
534→		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
535→		writeUpdateCache(cache)
536→		return fmt.Sprintf("Updating to %s...", latest)
537→	}
538→
539→	writeUpdateCache(cache)
540→	return ""
541→}
542→
543→func readUpdateCache() *updateCache {
544→	data, err := os.ReadFile(updateCacheFile)
545→	if err != nil {
546→		return nil
547→	}
548→	var c updateCache
549→	if err := json.Unmarshal(data, &c); err != nil {
550→		return nil
551→	}
552→	return &c
553→}
554→
555→func writeUpdateCache(c *updateCache) {
556→	data, err := json.Marshal(c)
557→	if err != nil {
558→		return
559→	}
560→	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
561→	os.WriteFile(updateCacheFile, data, 0644)
562→}
563→
564→// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
565→func fetchLatestVersion() string {
566→	client := &http.Client{Timeout: 3 * time.Second}
567→	resp, err := client.Get(githubReleasesURL)
568→	if err != nil {
569→		return ""
570→	}
571→	defer resp.Body.Close()
572→
573→	if resp.StatusCode != 200 {
574→		return ""
575→	}
576→
577→	var release struct {
578→		TagName string `json:"tag_name"`
579→	}
580→	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
581→		return ""
582→	}
583→	return release.TagName
584→}
585→
586→// runAutoUpdate runs the install script in the background. Returns true if launched.
587→func runAutoUpdate() bool {
588→	cmd := exec.Command("sh", "-c", "curl -fsSL https://install.nurge.sh | sh >/dev/null 2>&1")
589→	if err := cmd.Start(); err != nil {
590→		return false
591→	}
592→	// Don't wait — let it run in background
593→	go cmd.Wait()
594→	return true
595→}
596→
597→func capitalize(s string) string {
598→	if s == "" {
599→		return s
600→	}
601→	return strings.ToUpper(s[:1]) + s[1:]
602→}
603→
604→func formatCount(n int) string {
605→	if n >= 1000 {
606→		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
607→	}
608→	return fmt.Sprintf("%d", n)
609→}
