package cmd

import (
	"encoding/json"
	"fmt"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/project"
)

var configFormat string

var configCmd = &cobra.Command{
	Use:   "config",
	Short: "Manage nurge configuration",
}

var configShowCmd = &cobra.Command{
	Use:   "show",
	Short: "Show current configuration",
	RunE: func(cmd *cobra.Command, args []string) error {
		cfg, err := project.Load()
		if err != nil {
			return err
		}

		if configFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(cfg)
		}

		fmt.Printf("  Version: %d\n", cfg.Version)
		fmt.Printf("  Created: %s\n", cfg.CreatedAt)
		fmt.Printf("  Setup completed: %v\n", cfg.SetupCompleted)
		if len(cfg.Settings) > 0 {
			fmt.Println("  Settings:")
			for k, v := range cfg.Settings {
				fmt.Printf("    %s = %s\n", k, v)
			}
		}
		return nil
	},
}

var configSetCmd = &cobra.Command{
	Use:   "set <key> <value>",
	Short: "Set a configuration value",
	Args:  cobra.ExactArgs(2),
	RunE: func(cmd *cobra.Command, args []string) error {
		if err := project.Set(args[0], args[1]); err != nil {
			return err
		}
		fmt.Printf("  ✓ %s = %s\n", args[0], args[1])
		return nil
	},
}

func init() {
	configCmd.PersistentFlags().StringVar(&configFormat, "format", "", "Output format (json)")
	configCmd.AddCommand(configShowCmd)
	configCmd.AddCommand(configSetCmd)
	rootCmd.AddCommand(configCmd)
}

